import logging
import json
import azure.functions as func


app = func.FunctionApp(http_auth_level=func.AuthLevel.ANONYMOUS)


def add_cors_headers(headers=None):
    """Add CORS headers to response."""
    if headers is None:
        headers = {}
    headers["Access-Control-Allow-Origin"] = "*"
    headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, PATCH, OPTIONS"
    headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-Requested-With, Accept, Origin"
    headers["Access-Control-Max-Age"] = "86400"
    headers["Access-Control-Expose-Headers"] = "Content-Length, X-Request-Id"
    return headers


def create_response(body, status_code=200, mimetype="application/json"):
    """Create an HTTP response with CORS headers."""
    headers = add_cors_headers()
    if isinstance(body, (dict, list)):
        body = json.dumps(body)
    return func.HttpResponse(
        body=body,
        status_code=status_code,
        mimetype=mimetype,
        headers=headers
    )


@app.route(route="health", methods=["GET", "OPTIONS"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint."""
    logging.info("Health check endpoint called.")

    if req.method == "OPTIONS":
        return create_response("", status_code=204)

    return create_response({"status": "healthy", "message": "API is running"})


